pipeline.evaluate:
(async () => {
  const ps = Math.min(${{ args.limit }}, 30);
  const res = await fetch(
    'https://api.bilibili.com/x/web-interface/history/cursor?ps=' + ps + '&type=archive',
    { credentials: 'include' }
  );
  const payload = await res.json();
  const list = payload?.data?.list || [];

  function formatDuration(seconds) {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return m + ':' + s.toString().padStart(2, '0');
  }

  return list.map((item, i) => {
    const progress = item.progress || 0;
    const duration = item.duration || 0;
    let progressStr;
    if (progress < 0 || progress >= duration) {
      progressStr = 'completed';
    } else {
      const pct = duration > 0 ? Math.round(progress / duration * 100) : 0;
      progressStr = formatDuration(progress) + '/' + formatDuration(duration) + ' (' + pct + '%)';
    }
    return {
      rank: i + 1,
      title: item.title || '',
      author: item.author_name || '',
      progress: progressStr,
      url: item.history?.bvid ? 'https://www.bilibili.com/video/' + item.history.bvid : '',
    };
  });
})()
